module top_module(
    input [7:0] A,
    input [7:0] B,
    input [2:0] control,
    output reg [7:0] error_result
);always @(*) begin
        case (control)
            3'b000: error_result = A + B;
            3'b001: error_result = A - B;
            3'b010: error_result = A & B;
            3'b011: error_result = A | B;
            3'b100: error_result = A ^ B;
            3'b101: error_result = A << B;
            3'b110: error_result = A >> B;
            3'b111: error_result = A * B;
            default: error_result = 8'h00;
        endcase
    end

endmodule
